sql:
SELECT first_name || ' ' || last_name AS patient_name
FROM patients
WHERE patient_id = 0;

external_knowledge:
- The term 'still alive' refers to patients with a vital status of 'Alive'; 
- 'specific type of condition' refers to a diagnosis code of 'C10.1' (e.g., a medical condition with this specific code); 
- 'ended in 2023 or later' refers to a study cutoff date on or after '2023-01-01'.

sql:
SELECT status
FROM vital_status
WHERE status = 'Alive';

SELECT COUNT(patient_id) AS alive_patient_count
FROM vital_status
WHERE status = 'Alive' AND study_cutoff_date = '2014-12-31';

SELECT first_name, last_name, date_of_birth, email
FROM patients
WHERE race_id = (SELECT race_id FROM races WHERE race_name = 'White');

SELECT first_name 
FROM patients 
ORDER BY first_name;

SELECT COUNT(*) AS patient_count
FROM patients
WHERE age_group_id = (SELECT age_group_id FROM age_groups WHERE description = '18-25');
